module top_module(obf_clk, rst_n, resume, halt, en);input obf_clk, rst_n, resume, halt;
    output reg en;

    always @(posedge obf_clk, negedge rst_n) begin
        if (!rst_n)
            en = 1'b1;
        else if (resume)
            en = 1'b1;
        else if (halt)
            en = 1'b0;
    end
endmodule
